# Build Dashboard.html from component files — SINGLE style block$basePath = 'F:\CEO_DIRECTIVES\bod_meeting'# Read component files in order$cssBase = Get-Content "$basePath\Css_Base.html" -Raw -Encoding UTF8$cssComponents = Get-Content "$basePath\Css_Components.html" -Raw -Encoding UTF8$cssExtras = Get-Content "$basePath\Css_Extras.html" -Raw -Encoding UTF8$cssModal = Get-Content "$basePath\Css_Modal.html" -Raw -Encoding UTF8$cssResponsive = Get-Content "$basePath\Css_Responsive.html" -Raw -Encoding UTF8$cssTimeline = Get-Content "$basePath\Css_Timeline.html" -Raw -Encoding UTF8$htmlBody = Get-Content "$basePath\Html_Body.html" -Raw -Encoding UTF8$jsHelpers = Get-Content "$basePath\Js_Helpers.html" -Raw -Encoding UTF8$jsProcess = Get-Content "$basePath\Js_Process.html" -Raw -Encoding UTF8$jsCore = Get-Content "$basePath\Js_Core.html" -Raw -Encoding UTF8$jsApproval = Get-Content "$basePath\Js_Approval.html" -Raw -Encoding UTF8$jsDeptSchedule = Get-Content "$basePath\Js_DeptSchedule.html" -Raw -Encoding UTF8$jsEmail = Get-Content "$basePath\Js_Email.html" -Raw -Encoding UTF8$jsToast = Get-Content "$basePath\Js_Toast.html" -Raw -Encoding UTF8# SINGLE style block, TWO script blocks (same as working v850 pattern)$header = '<!DOCTYPE html><html lang="vi"><head>  <meta charset="UTF-8">  <meta name="viewport" content="width=device-width, initial-scale=1.0">  <title>BOD Meeting Dashboard</title>  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap" rel="stylesheet">  <style>'$endHead = '  </style></head><body>'$script1 = '<script>'$endScript1 = '</script>'$script2 = '<script>'$footer = '</script></body></html>'# All CSS in one block$allCss = @($cssBase, $cssComponents, $cssTimeline, $cssExtras, $cssModal, $cssResponsive) -join "`r`n"# Split JS into 2 blocks (matching old pattern)$jsBlock1 = @($jsHelpers, $jsProcess, $jsCore) -join "`r`n"$jsBlock2 = @($jsApproval, $jsDeptSchedule, $jsEmail, $jsToast) -join "`r`n"$parts = @(  $header,  $allCss,  $endHead,  $htmlBody,  $script1,  $jsBlock1,  $endScript1,  $script2,  $jsBlock2,  $footer)$dashboard = $parts -join "`r`n"# Write with UTF8 BOM  [System.IO.File]::WriteAllText("$basePath\Dashboard.html", $dashboard, [System.Text.UTF8Encoding]::new($true))$lineCount = ($dashboard -split "`n").Count$kb = [math]::Round($dashboard.Length / 1KB, 1)Write-Host "Dashboard.html generated: $lineCount lines, ${kb}KB (1 style + 2 script blocks)"